import React, { useState } from "react";
import "./App.css";

// Available fraction blocks
const FRACTIONS = [
  { numerator: 1, denominator: 2, color: "#60A5FA", label: "1/2" },
  { numerator: 1, denominator: 3, color: "#34D399", label: "1/3" },
  { numerator: 1, denominator: 4, color: "#F87171", label: "1/4" },
  { numerator: 1, denominator: 6, color: "#FBBF24", label: "1/6" },
  { numerator: 1, denominator: 8, color: "#A78BFA", label: "1/8" },
];

// --- COMPONENT: FREE PLAY (The original builder) ---
function FreePlay() {
  const [rows, setRows] = useState([[], [], []]);

  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();

  const handleDrop = (e, rowIndex) => {
    e.preventDefault();
    const fractionData = e.dataTransfer.getData("fraction");
    if (fractionData) {
      const fraction = JSON.parse(fractionData);
      const currentTotal = rows[rowIndex].reduce((sum, f) => sum + f.numerator / f.denominator, 0);
      const incomingValue = fraction.numerator / fraction.denominator;

      if (currentTotal + incomingValue <= 1.01) {
        const newRows = [...rows];
        newRows[rowIndex].push({ ...fraction, id: Math.random() });
        setRows(newRows);
      } else {
        alert("Oops! That piece is too big to fit in this row!");
      }
    }
  };

  const removeBlock = (rowIndex, blockIndex) => {
    const newRows = [...rows];
    newRows[rowIndex].splice(blockIndex, 1);
    setRows(newRows);
  };

  return (
    <div className="card">
      <p className="instruction-text">
        Drag the colorful blocks into the empty rows. Can you make two rows exactly the same length?
      </p>

      {/* Toolbox */}
      <div className="toolbox">
        {FRACTIONS.map((frac, index) => (
          <div 
            key={index} 
            draggable 
            onDragStart={(e) => handleDragStart(e, frac)}
            className="fraction-block"
            style={{ backgroundColor: frac.color }}
          >
            {frac.label}
          </div>
        ))}
      </div>

      <div className="row-container">
        <strong className="row-label">This is 1 Whole:</strong>
        <div className="whole-bar">1 Whole</div>
      </div>

      {rows.map((row, rowIndex) => (
        <div key={rowIndex} className="row-container">
          <strong className="row-label">Row {rowIndex + 1}:</strong>
          <div 
            onDragOver={handleDragOver} 
            onDrop={(e) => handleDrop(e, rowIndex)}
            className="drop-zone"
          >
            {row.length === 0 && <span className="drop-zone-placeholder">Drag blocks here!</span>}
            {row.map((block, blockIndex) => (
              <div 
                key={block.id} 
                onClick={() => removeBlock(rowIndex, blockIndex)} 
                title="Click to remove"
                className="placed-block"
                style={{ 
                  width: `${(block.numerator / block.denominator) * 100}%`, 
                  backgroundColor: block.color 
                }}
              >
                {block.label}
              </div>
            ))}
          </div>
        </div>
      ))}
      <div style={{ textAlign: "center", marginTop: "20px" }}>
        <button onClick={() => setRows([[], [], []])} className="btn-danger">
          🗑️ Clear Board
        </button>
      </div>
    </div>
  );
}

// --- COMPONENT: CHALLENGE MODE ---
const CHALLENGES = [
  { id: 1, text: "Can you make 1/2 using only Red 1/4 blocks?", target: 0.5 },
  { id: 2, text: "Make 1 Whole using only Green 1/3 blocks!", target: 1.0 },
  { id: 3, text: "Can you make 1/2 using only Purple 1/8 blocks?", target: 0.5 },
  { id: 4, text: "Mix and match! Make 1 Whole using different sized blocks.", target: 1.0 }
];

function ChallengeMode() {
  const [currentLevel, setCurrentLevel] = useState(0);
  const [row, setRow] = useState([]);
  const [isSuccess, setIsSuccess] = useState(false);

  const activeChallenge = CHALLENGES[currentLevel];

  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();

  const handleDrop = (e) => {
    e.preventDefault();
    if (isSuccess) return; // Stop adding if already won

    const fractionData = e.dataTransfer.getData("fraction");
    if (fractionData) {
      const fraction = JSON.parse(fractionData);
      const currentTotal = row.reduce((sum, f) => sum + f.numerator / f.denominator, 0);
      const incomingValue = fraction.numerator / fraction.denominator;

      if (currentTotal + incomingValue <= 1.01) {
        const newRow = [...row, { ...fraction, id: Math.random() }];
        setRow(newRow);
        checkAnswer(newRow);
      } else {
        alert("Oops! That's too big!");
      }
    }
  };

  const removeBlock = (blockIndex) => {
    if (isSuccess) return;
    const newRow = [...row];
    newRow.splice(blockIndex, 1);
    setRow(newRow);
    checkAnswer(newRow);
  };

  const checkAnswer = (currentRow) => {
    const total = currentRow.reduce((sum, f) => sum + f.numerator / f.denominator, 0);
    // Use Math.abs for floating point comparison
    if (Math.abs(total - activeChallenge.target) < 0.01) {
      setIsSuccess(true);
    }
  };

  const nextChallenge = () => {
    setRow([]);
    setIsSuccess(false);
    setCurrentLevel((prev) => (prev + 1) % CHALLENGES.length);
  };

  return (
    <div className="card" style={{ textAlign: "center" }}>
      <h2 className="challenge-header">Level {currentLevel + 1}: {activeChallenge.text}</h2>

      {/* Toolbox */}
      <div className="toolbox">
        {FRACTIONS.map((frac, index) => (
          <div 
            key={index} 
            draggable={!isSuccess}
            onDragStart={(e) => handleDragStart(e, frac)}
            className={`fraction-block ${isSuccess ? 'disabled' : ''}`}
            style={{ backgroundColor: frac.color }}
          >
            {frac.label}
          </div>
        ))}
      </div>

      {/* Target Reference Line (Visual hint for the kid) */}
      <div className="target-container">
         <div className="target-line" style={{ width: `${activeChallenge.target * 100}%` }}>
            <span className="target-label">Target Goal</span>
         </div>
      </div>

      {/* Challenge Drop Zone */}
      <div 
        onDragOver={handleDragOver} 
        onDrop={handleDrop}
        className={`drop-zone ${isSuccess ? 'success' : ''}`}
        style={{ height: '80px' }}
      >
        {row.length === 0 && <span className="drop-zone-placeholder">Build your answer here!</span>}

        {row.map((block, blockIndex) => (
          <div 
            key={block.id} 
            onClick={() => removeBlock(blockIndex)}
            className="placed-block"
            style={{ 
              width: `${(block.numerator / block.denominator) * 100}%`, 
              backgroundColor: block.color 
            }}
          >
            {block.label}
          </div>
        ))}
      </div>

      {isSuccess && (
        <div className="success-message">
          <h3 className="success-title">🎉 You did it! Great job! 🎉</h3>
          <button onClick={nextChallenge} className="btn-primary">
            Next Challenge ➡️
          </button>
        </div>
      )}
    </div>
  );
}

// --- MAIN APP COMPONENT (Handles the Menu) ---
export default function App() {
  const [activeTab, setActiveTab] = useState("free"); // "free" or "challenge"

  return (
    <div className="app-container">
      <h1 className="app-title">🍕 Fraction Fun Builder! 🍕</h1>
      <p className="app-subtitle">Learn fractions by playing with blocks!</p>

      {/* Navigation Menu */}
      <div className="nav-menu">
        <button 
          onClick={() => setActiveTab("free")}
          className={`nav-button ${activeTab === "free" ? "active" : ""}`}
        >
          🎈 Free Play
        </button>
        <button 
          onClick={() => setActiveTab("challenge")}
          className={`nav-button challenge ${activeTab === "challenge" ? "active" : ""}`}
        >
          🏆 Challenges
        </button>
      </div>

      {/* Show the selected page */}
      {activeTab === "free" ? <FreePlay /> : <ChallengeMode />}
    </div>
  );
}
